pub struct ServiceDef {
    pub name: &'static str,
    pub port: Option<u16>,
    pub health_proto: HealthProto,
    pub health_path: &'static str,
}
pub fn service_definitions() -> Vec<ServiceDef> {
    vec![
        ServiceDef {
            name: "corvia-server",
            port: Some(8020),
            health_proto: HealthProto::Http,
            health_path: "/health",
        },
        ServiceDef {
            name: "corvia-inference",
            port: Some(8030),
            health_proto: HealthProto::Grpc,
            health_path: "",
        },
    ]
}
